insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('computer-science:2-2-3d-sql:mcq:c474b325', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'mcq', 'mcq', 1, '{"question": "What does the WHERE keyword control?", "options": ["Which rows are returned, based on a condition", "Which fields (columns) are returned", "Which table the data is read from", "Whether the values inside the table are permanently sorted into a fixed order"]}'::jsonb, '{"answer": 0, "explain": "WHERE filters ROWS by a condition. SELECT is for fields, and FROM names the table."}'::jsonb),
('computer-science:2-2-3d-sql:mcq:adb6c25f', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'mcq', 'mcq', 1, '{"question": "What does  SELECT * FROM Squad  return?", "options": ["Every field, for every row in the Squad table", "Only the first field, for every row in the Squad table", "Every field, but only for the very first row in the Squad table", "Nothing at all, because * is not a valid symbol inside a SELECT statement"]}'::jsonb, '{"answer": 0, "explain": "* means ''all fields''. With no WHERE clause, every row is also returned — so this returns the whole table."}'::jsonb),
('computer-science:2-2-3d-sql:mcq:b16de106', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'mcq', 'mcq', 1, '{"question": "A table Album stores AlbumID, Title, Genre, Year and Price. Which query correctly returns the Title of every album priced at exactly 10?", "options": ["SELECT Title FROM Album WHERE Price = 10", "SELECT Title FROM Album WHERE Price == 10", "SELECT Price FROM Album WHERE Title = 10", "SELECT Title FROM Album WHERE Price = \"10\""]}'::jsonb, '{"answer": 0, "explain": "SQL uses a single = for comparison, and Price is numeric so it needs no quotation marks: WHERE Price = 10."}'::jsonb),
('computer-science:2-2-3d-sql:mcq:974ac9c8', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'mcq', 'mcq', 1, '{"question": "Which of these correctly compares two values for ''not equal to'' in SQL?", "options": ["A less-than sign directly followed by a greater-than sign", "A double equals sign", "An equals sign directly followed by an exclamation mark, since this is the ordering most students expect ''not equal to'' to use", "An exclamation mark directly followed by an equals sign"]}'::jsonb, '{"answer": 0, "explain": "SQL (as used in J277) writes ''not equal to'' with a less-than sign followed immediately by a greater-than sign."}'::jsonb),
('computer-science:2-2-3d-sql:mcq:b651b899', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'mcq', 'mcq', 1, '{"question": "A WHERE condition uses the operator meaning ''less than or equal to''. Which is it?", "options": ["A less-than sign directly followed by an equals sign", "A less-than sign on its own, never followed by an equals sign", "A greater-than sign directly followed by an equals sign", "A less-than sign directly followed by a greater-than sign"]}'::jsonb, '{"answer": 0, "explain": "''Less than or equal to'' is written as a less-than sign followed by an equals sign — it includes an exact match as well as smaller values."}'::jsonb),
('computer-science:2-2-3d-sql:mcq:dac1b5ff', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'mcq', 'mcq', 1, '{"question": "Which of these text comparisons is written correctly in SQL?", "options": ["WHERE Sport = \"Netball\"", "WHERE Sport = Netball", "WHERE \"Sport\" = Netball", "WHERE Sport == \"Netball\", since two consecutive equals signs are always required whenever text is compared"]}'::jsonb, '{"answer": 0, "explain": "Text values must be inside quotation marks: WHERE Sport = \"Netball\". SQL also compares with a single =, not ==."}'::jsonb),
('computer-science:2-2-3d-sql:mcq:34babc85', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'mcq', 'mcq', 1, '{"question": "Two conditions are combined with AND. What must be true for a row to be returned?", "options": ["Both conditions must be true for that row", "At least one of the two conditions must be true", "Neither condition needs to be true", "Exactly one of the two conditions must be true, but not both at the same time"]}'::jsonb, '{"answer": 0, "explain": "AND requires every listed condition to be true for a row to be included."}'::jsonb),
('computer-science:2-2-3d-sql:mcq:9d1c4933', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'mcq', 'mcq', 1, '{"question": "Two conditions are combined with OR. What must be true for a row to be returned?", "options": ["At least one of the two conditions must be true", "Both conditions must be true at exactly the same time for the row to qualify", "Neither condition needs to be true for the row to be returned", "The row must fail both conditions before it can possibly be returned"]}'::jsonb, '{"answer": 0, "explain": "OR needs only ONE of the conditions to be true — unlike AND, which needs every condition to be true."}'::jsonb),
('computer-science:2-2-3d-sql:mcq:a8f327d5', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'mcq', 'mcq', 1, '{"question": "In OCR''s J277 specification, which of these SQL keywords is actually required?", "options": ["WHERE", "INSERT", "UPDATE", "DELETE"]}'::jsonb, '{"answer": 0, "explain": "J277 only requires SELECT, FROM and WHERE — commands that add, change or delete data are outside the specification."}'::jsonb),
('computer-science:2-2-3d-sql:mcq:983ed4a3', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'mcq', 'mcq', 1, '{"question": "A table stores a Name field and an Age field. Which keyword names the table itself inside a query?", "options": ["FROM", "SELECT", "WHERE", "TABLE"]}'::jsonb, '{"answer": 0, "explain": "FROM names the table a query reads from. SELECT chooses fields, and WHERE holds the condition."}'::jsonb),
('computer-science:2-2-3d-sql:mcq:52b03df8', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'mcq', 'mcq', 1, '{"question": "A query uses the condition ''Age is strictly greater than 15''. Would a player whose Age is exactly 15 be included?", "options": ["No — a strict ''greater than'' excludes the boundary value itself", "Yes — ''greater than'' always includes the exact boundary value too", "Only if the value 15 is also written in quotation marks", "Yes, but only when the field being compared is text rather than a number"]}'::jsonb, '{"answer": 0, "explain": "A strict greater-than excludes the boundary. A player aged exactly 15 would need ''greater than or equal to 15'' to be included."}'::jsonb),
('computer-science:2-2-3d-sql:tf:064dacf8', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'tf', 'tf', 1, '{"question": "SELECT chooses which rows are returned by a query."}'::jsonb, '{"answer": false, "explain": "SELECT chooses which FIELDS (columns) are returned, not which rows — that is WHERE''s job."}'::jsonb),
('computer-science:2-2-3d-sql:tf:5af996f6', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'tf', 'tf', 1, '{"question": "WHERE filters which rows are returned, based on a condition."}'::jsonb, '{"answer": true, "explain": "Correct — WHERE holds the condition that decides which rows (records) are included in the result."}'::jsonb),
('computer-science:2-2-3d-sql:tf:20a74794', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'tf', 'tf', 1, '{"question": "SELECT * FROM Squad returns only the Name field for every row."}'::jsonb, '{"answer": false, "explain": "* means ''every field'', not just Name — SELECT * FROM Squad returns all 5 fields for every row."}'::jsonb),
('computer-science:2-2-3d-sql:tf:7ff79d9d', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'tf', 'tf', 1, '{"question": "Text values in a WHERE condition must be written inside quotation marks."}'::jsonb, '{"answer": true, "explain": "Correct — e.g. WHERE Position = \"Striker\". Numeric values do not need quotation marks."}'::jsonb),
('computer-science:2-2-3d-sql:tf:ded019ad', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'tf', 'tf', 1, '{"question": "In SQL, a single equals sign is used to compare whether two values are equal."}'::jsonb, '{"answer": true, "explain": "Correct — SQL uses one equals sign for a comparison, unlike ERL''s double equals sign for comparing two values."}'::jsonb),
('computer-science:2-2-3d-sql:tf:6ab871f0', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'tf', 'tf', 1, '{"question": "Combining two conditions with AND means a row only needs to meet one of them to be returned."}'::jsonb, '{"answer": false, "explain": "That describes OR. AND requires a row to meet BOTH conditions before it is returned."}'::jsonb),
('computer-science:2-2-3d-sql:tf:7eb0af08', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'tf', 'tf', 1, '{"question": "OCR''s J277 SQL only requires SELECT, FROM and WHERE — not INSERT, UPDATE or DELETE."}'::jsonb, '{"answer": true, "explain": "Correct — J277 SQL is read-only querying. Commands that edit data are outside the specification."}'::jsonb),
('computer-science:2-2-3d-sql:tf:bf23d932', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'tf', 'tf', 1, '{"question": "A strict ''greater than'' condition on Age would include a row where Age matches the boundary value exactly."}'::jsonb, '{"answer": false, "explain": "A strict ''greater than'' excludes the boundary value. A row matching it exactly would need ''greater than or equal to'' (or ''equal to'') to be included."}'::jsonb),
('computer-science:2-2-3d-sql:learn:3de32522', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'learn', 'mcq', 1, '{"readingTitle": "What is SQL, and what is a database table?", "reading": "<h4>Querying data stored in a table</h4>\n<ul>\n<li><strong>SQL</strong> (Structured Query Language) is used to ask a database questions about the data it stores — this is called <strong>querying</strong> the database.</li>\n<li>A database <strong>table</strong> stores data in rows and columns. Each column is a <strong>field</strong> (e.g. Name, Age). Each row is a <strong>record</strong> — one complete set of field values.</li>\n<li>For OCR J277 you only need three keywords: <code>SELECT</code>, <code>FROM</code> and <code>WHERE</code>.</li>\n</ul>\n<p>Table <strong>Squad</strong> (a school football club):</p>\n<div class=\"code-block\">PlayerID | Name   | Position   | Age | Goals\n1        | Alex   | Striker    | 17  | 12\n2        | Priya  | Midfielder | 15  | 5\n3        | Sam    | Defender   | 16  | 1\n4        | Jordan | Striker    | 14  | 8\n5        | Kim    | Midfielder | 17  | 3\n6        | Reo    | Defender   | 15  | 0</div>\n<ul><li>This table has <strong>5 fields</strong> (PlayerID, Name, Position, Age, Goals) and <strong>6 records</strong> (one row per player).</li></ul>", "question": "In the Squad table, what is a single row — for example the whole row for Alex — called?", "options": ["A record", "A field", "A query", "A keyword, since every row must always begin with a valid SQL keyword before any data can be stored in it"]}'::jsonb, '{"answer": 0, "explain": "A row of a table (one complete set of field values, such as Alex''s whole entry) is called a record. A column, such as Name or Age, is a field."}'::jsonb),
('computer-science:2-2-3d-sql:learn:4f49ffbd', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'learn', 'mcq', 1, '{"readingTitle": "SELECT and FROM — choosing fields and a table", "reading": "<h4>Naming which columns you want, and which table to read</h4>\n<ul>\n<li><code>SELECT</code> — lists which field(s) (columns) the query should return.</li>\n<li><code>FROM</code> — names the table the query reads its data from.</li>\n<li>Field names are separated with commas if more than one is needed.</li>\n</ul>\n<p>Query: <code>SELECT Name, Position FROM Squad</code></p>\n<div class=\"code-block\">Name   | Position\nAlex   | Striker\nPriya  | Midfielder\nSam    | Defender\nJordan | Striker\nKim    | Midfielder\nReo    | Defender</div>\n<ul><li>With no WHERE clause, <strong>every</strong> record (row) in the table is returned — just with only the chosen fields shown.</li></ul>", "question": "What does  SELECT Name, Position FROM Squad  return, using the Squad table above?", "options": ["The Name and Position fields, for all six players", "Only the Name field, for all six players", "The Name and Position fields, but only for the very first player in the table", "Every field in the Squad table, for all six players, because FROM always means ''return every field''"]}'::jsonb, '{"answer": 0, "explain": "SELECT Name, Position chooses just those two fields. With no WHERE clause, every row (all six players) is returned."}'::jsonb),
('computer-science:2-2-3d-sql:learn:357c17bd', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'learn', 'mcq', 1, '{"readingTitle": "SELECT * — all fields", "reading": "<h4>The wildcard that means ''every field''</h4>\n<ul>\n<li><code>SELECT *</code> returns <strong>every field</strong> in the table, instead of naming them one by one.</li>\n<li>The <code>*</code> is a shortcut here — it does <strong>not</strong> mean multiply, even though it''s the same symbol used for multiplication elsewhere.</li>\n</ul>\n<p>Query: <code>SELECT * FROM Squad WHERE Position = \"Defender\"</code></p>\n<div class=\"code-block\">PlayerID | Name | Position | Age | Goals\n3        | Sam  | Defender | 16  | 1\n6        | Reo  | Defender | 15  | 0</div>\n<ul><li>All 5 fields are shown, but only for the 2 rows that match the WHERE condition.</li></ul>", "question": "What does the  *  symbol mean inside  SELECT * FROM Squad ?", "options": ["Return every field in the table", "Multiply every numeric field together before returning it", "Return only the first field in the table", "Return every table stored in the whole database at once, not just Squad"]}'::jsonb, '{"answer": 0, "explain": "In a SELECT statement, * means ''every field'' — it is not the multiplication operator here."}'::jsonb),
('computer-science:2-2-3d-sql:learn:745d065a', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'learn', 'mcq', 1, '{"readingTitle": "WHERE — filtering with a single condition", "reading": "<h4>Choosing which rows come back</h4>\n<ul>\n<li><code>WHERE</code> adds a <strong>condition</strong> — only rows for which the condition is true are returned.</li>\n<li>Comparison operators used in a WHERE condition: <code>=</code> (equal to), <code>&lt;</code> (less than), <code>&gt;</code> (greater than), <code>&lt;=</code> (less than or equal to), <code>&gt;=</code> (greater than or equal to), <code>&lt;&gt;</code> (not equal to).</li>\n</ul>\n<p>Query: <code>SELECT Name FROM Squad WHERE Position = \"Striker\"</code></p>\n<div class=\"code-block\">Name\nAlex\nJordan</div>\n<ul><li>Only Alex and Jordan play Striker, so only their names are returned — Priya, Sam, Kim and Reo are filtered out.</li></ul>", "question": "Using the Squad table, what does  SELECT Name FROM Squad WHERE Age &gt; 16  return?", "options": ["Alex and Kim (both aged 17)", "Sam only (aged 16)", "Alex, Sam and Kim", "Every player in the table, since WHERE only affects which fields are shown, never which rows"]}'::jsonb, '{"answer": 0, "explain": "Age &gt; 16 is strict — it excludes 16 itself. Only Alex (17) and Kim (17) have an Age greater than 16; Sam (16) is excluded."}'::jsonb),
('computer-science:2-2-3d-sql:learn:219a343f', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'learn', 'mcq', 1, '{"readingTitle": "Comparing text and comparing numbers", "reading": "<h4>Quotation marks matter for text, not for numbers</h4>\n<ul>\n<li>A <strong>text</strong> value in a WHERE condition must be written inside <strong>quotation marks</strong>, e.g. <code>WHERE Position = \"Striker\"</code>.</li>\n<li>A <strong>numeric</strong> value is written with <strong>no</strong> quotation marks, e.g. <code>WHERE Age &gt;= 16</code>.</li>\n<li>SQL uses a <strong>single</strong> <code>=</code> to test whether two values are equal — unlike OCR''s Exam Reference Language, which uses <code>==</code> for a comparison.</li>\n</ul>\n<p><code>WHERE Position = Striker</code> (no quotation marks) is <strong>not valid SQL</strong> — Striker would be read as a field name, not a piece of text.</p>", "question": "Which of these is written correctly as an SQL condition?", "options": ["WHERE Sport = \"Netball\"", "WHERE Sport = Netball", "WHERE \"Sport\" = Netball", "WHERE Sport == \"Netball\", since SQL always compares two values using a double equals sign, exactly like most other programming languages"]}'::jsonb, '{"answer": 0, "explain": "Text values need quotation marks: WHERE Sport = \"Netball\". SQL also uses a single = for comparison, not ==."}'::jsonb),
('computer-science:2-2-3d-sql:learn:23661ce2', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'learn', 'mcq', 1, '{"readingTitle": "Combining conditions with AND", "reading": "<h4>Both conditions must be true</h4>\n<ul>\n<li><code>AND</code> combines two (or more) conditions. A row is only returned if <strong>every</strong> condition is true for that row.</li>\n<li>Adding more conditions with AND can only keep the same number of rows or <strong>reduce</strong> them — it never returns more rows than a single condition alone.</li>\n</ul>\n<p>Query: <code>SELECT Name FROM Squad WHERE Position = \"Striker\" AND Age &gt;= 15</code></p>\n<div class=\"code-block\">Name\nAlex</div>\n<ul><li>Alex (Striker, 17) meets both conditions. Jordan is a Striker too, but he is only 14, so he fails the Age condition and is left out.</li></ul>", "question": "Why does Jordan NOT appear in the result of  SELECT Name FROM Squad WHERE Position = \"Striker\" AND Age &gt;= 15 ?", "options": ["He meets the Position condition but fails the Age condition, and AND needs both to be true", "He fails both conditions completely, since he does not play Striker", "AND only ever checks the first condition listed, so his Age is never actually tested", "He is not stored in the Squad table at all, so he cannot appear in any query result whatsoever"]}'::jsonb, '{"answer": 0, "explain": "Jordan is a Striker (passes condition 1) but is 14, not >= 15 (fails condition 2). AND requires BOTH conditions to be true, so he is excluded."}'::jsonb),
('computer-science:2-2-3d-sql:learn:19b71350', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'learn', 'mcq', 1, '{"readingTitle": "Combining conditions with OR", "reading": "<h4>At least one condition must be true</h4>\n<ul>\n<li><code>OR</code> combines two (or more) conditions. A row is returned if <strong>at least one</strong> of the conditions is true for that row.</li>\n<li>Adding conditions with OR can only keep the same number of rows or <strong>increase</strong> them, since more rows now have a way to qualify.</li>\n</ul>\n<p>Query: <code>SELECT Name FROM Squad WHERE Position = \"Striker\" OR Goals &gt;= 5</code></p>\n<div class=\"code-block\">Name\nAlex\nPriya\nJordan</div>\n<ul><li>Alex and Jordan qualify because they play Striker. Priya qualifies too — not because of her position, but because she has scored 5 goals.</li></ul>", "question": "In  SELECT Name FROM Squad WHERE Position = \"Striker\" OR Goals &gt;= 5 , why is Priya included even though she plays Midfielder?", "options": ["She meets the second condition (Goals >= 5), and OR only needs one condition to be true", "OR requires every listed condition to be true, and Priya happens to meet both of them", "She is included by mistake, because Midfielder players can never appear in any query result", "Her PlayerID happens to be an odd number, which is unrelated to either condition in the query"]}'::jsonb, '{"answer": 0, "explain": "OR needs only ONE condition to be true. Priya fails the Position condition but has 5 goals, which satisfies Goals >= 5."}'::jsonb),
('computer-science:2-2-3d-sql:learn:ee5dc3bf', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'learn', 'mcq', 1, '{"readingTitle": "Reading a query''s result from a table", "reading": "<h4>Work out the columns, then the rows</h4>\n<ul>\n<li>To answer \"what does this query return?\", work through it in order:</li>\n<li><strong>1. SELECT</strong> — which columns will appear in the answer?</li>\n<li><strong>2. FROM</strong> — which table are you reading?</li>\n<li><strong>3. WHERE</strong> — go through the table row by row, checking the condition against that row''s values.</li>\n</ul>\n<p>Table <strong>Album</strong>:</p>\n<div class=\"code-block\">AlbumID | Title      | Genre | Year | Price\n1       | Skyline    | Pop   | 2019 | 8\n2       | Wavelength | Rock  | 2021 | 10\n3       | Horizon    | Pop   | 2022 | 12\n4       | Ember      | Rock  | 2018 | 6\n5       | Tidal      | Jazz  | 2020 | 9</div>\n<p>Query: <code>SELECT Title, Price FROM Album WHERE Genre = \"Pop\" AND Price &gt; 9</code></p>\n<div class=\"code-block\">Title   | Price\nHorizon | 12</div>\n<ul><li>Skyline is Pop, but its Price (8) is not greater than 9, so it is filtered out. Horizon is Pop and its Price (12) is greater than 9, so it is the only row returned.</li></ul>", "question": "Using the Album table above, why does Ember NOT appear in the result of  SELECT Title FROM Album WHERE Genre = \"Rock\" AND Price &gt; 9 ?", "options": ["It is Rock, but its Price (6) is not greater than 9, so it fails the Price condition", "It is Pop, not Rock, so it fails the Genre condition", "Its Price (6) is greater than 9, but its Genre is not Rock", "AND blocks every single row in the Album table from ever being returned, regardless of any condition"]}'::jsonb, '{"answer": 0, "explain": "Ember''s Genre is Rock (passes condition 1), but its Price is 6, which is not greater than 9 (fails condition 2). AND needs both, so Ember is excluded."}'::jsonb),
('computer-science:2-2-3d-sql:learn:9176d52b', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'learn', 'mcq', 1, '{"readingTitle": "Writing a query from a description", "reading": "<h4>Turning English into SQL</h4>\n<ul>\n<li>Exam questions describe what''s needed in words. Break the description into three parts, in this order:</li>\n<li><strong>Which fields?</strong> → after SELECT.</li>\n<li><strong>Which table?</strong> → after FROM.</li>\n<li><strong>Which rows?</strong> (any condition) → after WHERE.</li>\n</ul>\n<p>\"Show the title and year of every Rock album costing less than 10\":</p>\n<div class=\"code-block\">SELECT Title, Year FROM Album WHERE Genre = \"Rock\" AND Price &lt; 10</div>\n<p>Checking against the Album table: Wavelength is Rock but costs 10 (not less than 10), so it''s excluded. Ember is Rock and costs 6, so it is the only row returned — Title = Ember, Year = 2018.</p>", "question": "A question asks for a query that shows every field for members who scored more than 5 goals. Which part of the query names the table?", "options": ["The part after FROM", "The part after SELECT", "The part after WHERE", "The condition itself, since a condition always states which table it is meant to apply to"]}'::jsonb, '{"answer": 0, "explain": "FROM names the table. SELECT chooses fields, and WHERE holds the condition — here, Goals > 5."}'::jsonb),
('computer-science:2-2-3d-sql:learn:d4861d65', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'learn', 'mcq', 1, '{"readingTitle": "What SQL in J277 can and can''t do", "reading": "<h4>J277 SQL is for reading data, not changing it</h4>\n<ul>\n<li>For OCR J277 you only need to <strong>read</strong> data using SELECT, FROM and WHERE — this is sometimes called <strong>querying</strong>.</li>\n<li>You do <strong>not</strong> need commands that add, change or delete data (such as INSERT, UPDATE or DELETE) — they are outside the J277 specification.</li>\n<li>Running a SELECT query never changes anything stored in the table — it only returns a <strong>view</strong> of the data that matches the query.</li>\n</ul>", "question": "Does running  SELECT Name FROM Squad WHERE Age &gt; 16  change any data stored in the Squad table?", "options": ["No — SELECT only reads and returns data; it does not change the table", "Yes — it permanently deletes every row that fails the WHERE condition", "Yes — it changes the Age of every player to exactly 16", "No, but only because this particular query does not include the keyword UPDATE"]}'::jsonb, '{"answer": 0, "explain": "A SELECT query only reads and returns matching data — the Squad table itself is left completely unchanged."}'::jsonb),
('computer-science:2-2-3d-sql:learn:0fb1124d', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'learn', 'mcq', 1, '{"readingTitle": "The comparison operators, recapped", "reading": "<h4>The six comparison operators</h4>\n<div class=\"code-block\">Equals (=)                        — true when the two values are exactly the same\nNot equal to (&lt;&gt;)           — true when the two values are different\nGreater than (&gt;)               — true when the left value is bigger\nLess than (&lt;)                  — true when the left value is smaller\nGreater than or equal to (&gt;=)  — also true on an exact match\nLess than or equal to (&lt;=)     — also true on an exact match</div>\n<ul>\n<li>These work on both numeric fields (e.g. <code>Age &gt;= 16</code>) and text fields (e.g. <code>Position &lt;&gt; \"Striker\"</code>, meaning \"not a Striker\").</li>\n<li>Remember: <code>&gt;</code> and <code>&lt;</code> are <strong>strict</strong> — they exclude the boundary value itself. <code>&gt;=</code> and <code>&lt;=</code> <strong>include</strong> the boundary value.</li>\n</ul>", "question": "Which operator would you use to find every player who is NOT a Defender?", "options": ["Not equal to", "Equal to", "Greater than or equal to", "Less than or equal to, since this is the operator most often confused with the one that means ''not equal to'' in SQL"]}'::jsonb, '{"answer": 0, "explain": "Not equal to (written <>) is what''s needed. WHERE Position <> \"Defender\" returns every row that is NOT a Defender."}'::jsonb),
('computer-science:2-2-3d-sql:misc:db2eb273', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking the * in SELECT * means ''multiply'', like it does in ordinary arithmetic.</p><p><strong>✅ The correct idea:</strong> Inside a <code>SELECT</code> statement, <code>*</code> means <strong>''every field''</strong> — it has nothing to do with multiplication here.</p>", "question": "What does  SELECT * FROM Album  mean?", "options": ["Return every field, for every row in the Album table", "Multiply together every numeric field in the Album table", "Return only the AlbumID field, for every row", "Return every field, but only for the row with the smallest AlbumID"]}'::jsonb, '{"answer": 0, "explain": "* is a shortcut meaning ''every field'' inside SELECT — not the multiplication operator."}'::jsonb),
('computer-science:2-2-3d-sql:misc:cc18997e', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Forgetting the quotation marks around a text value in a WHERE condition.</p><p><strong>✅ The correct idea:</strong> A <strong>text</strong> value (like a name or a genre) must be inside quotation marks, e.g. <code>WHERE Genre = \"Jazz\"</code>. A <strong>numeric</strong> value, like a Price or an Age, does not need them.</p>", "question": "Which condition is written correctly?", "options": ["WHERE Genre = \"Jazz\"", "WHERE Genre = Jazz", "WHERE \"Genre\" = Jazz", "WHERE Genre equals \"Jazz\" equals true, since a condition must always restate whether or not it is true"]}'::jsonb, '{"answer": 0, "explain": "Text values need quotation marks around them: WHERE Genre = \"Jazz\"."}'::jsonb),
('computer-science:2-2-3d-sql:misc:ccdb1e6f', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking that SQL, as covered in J277, can be used to add, edit or delete data in a table.</p><p><strong>✅ The correct idea:</strong> For OCR J277 you only need to <strong>read</strong> data with SELECT, FROM and WHERE. Commands that change data (like INSERT, UPDATE or DELETE) are outside the specification — a SELECT query never edits the table it reads from.</p>", "question": "What happens to the Squad table after a SELECT query with a WHERE condition on Age runs against it?", "options": ["Nothing — the table is completely unchanged; the query only returns matching data", "Every row failing the condition is permanently and irreversibly removed from the table itself", "Every player''s Age is updated to a new value", "A brand new table is automatically created to store the query''s result"]}'::jsonb, '{"answer": 0, "explain": "SELECT only reads data and returns a result — it never changes what is stored in the table."}'::jsonb),
('computer-science:2-2-3d-sql:misc:11d191e5', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Mixing up SELECT (which picks fields/columns) with WHERE (which picks rows).</p><p><strong>✅ The correct idea:</strong> <strong>SELECT</strong> controls which <strong>fields (columns)</strong> come back. <strong>WHERE</strong> controls which <strong>rows (records)</strong> come back, based on a condition. They filter two completely different things.</p>", "question": "Which keyword would you change to return fewer COLUMNS, without changing which rows are returned?", "options": ["SELECT", "WHERE", "FROM", "AND, since that is the only keyword able to control how many columns a query returns"]}'::jsonb, '{"answer": 0, "explain": "SELECT controls which fields (columns) are returned. Changing WHERE would affect rows, not columns."}'::jsonb),
('computer-science:2-2-3d-sql:misc:e969e48c', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking AND and OR behave the same way, or mixing up which one requires both conditions.</p><p><strong>✅ The correct idea:</strong> <strong>AND</strong> needs <strong>every</strong> condition to be true for a row to be returned — adding more conditions with AND can only reduce the rows returned. <strong>OR</strong> needs only <strong>one</strong> condition to be true — adding more conditions with OR can only increase the rows returned.</p>", "question": "Compared to a single Position condition on its own, would adding a second condition joined with AND ever return MORE rows?", "options": ["No — AND can only keep the same rows or return fewer of them, never more", "Yes — AND always returns more rows than a single condition on its own", "Yes, but only if the second condition uses a text value rather than a number", "It depends entirely on which table the query happens to be written against"]}'::jsonb, '{"answer": 0, "explain": "AND narrows a query down — every extra condition can only keep the same rows or remove some, never add rows that failed the first condition."}'::jsonb),
('computer-science:2-2-3d-sql:misc:4f25fd8b', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Assuming a strict ''greater than'' or ''less than'' condition includes the exact boundary value itself.</p><p><strong>✅ The correct idea:</strong> A strict <strong>greater than</strong> or <strong>less than</strong> excludes the boundary value. Only <strong>greater/less than or equal to</strong> includes it. A strict ''Age greater than 16'' excludes a player who is exactly 16; ''Age greater than or equal to 16'' includes them.</p>", "question": "A condition uses a strict ''Goals greater than 5''. Would a player with exactly 5 goals be included?", "options": ["No — a strict ''greater than'' excludes the value 5 itself", "Yes — ''greater than'' always includes the exact boundary value too", "Only if the value 5 is written inside quotation marks", "Yes, but only for a player whose Position happens to be Striker"]}'::jsonb, '{"answer": 0, "explain": "A strict ''greater than'' excludes the boundary. A player with exactly 5 goals would need ''greater than or equal to 5'' (or ''equal to 5'') to be included."}'::jsonb),
('computer-science:2-2-3d-sql:tips:c893f5de', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'tips', 'mcq', 1, '{"readingTitle": "tip — Reading a query''s result systematically", "reading": "<p>\"What does this query return?\" is one of the most common SQL question types. Work through it in a fixed order, every time:</p>\n<ul>\n<li><strong>1. SELECT</strong> — which columns will the answer have?</li>\n<li><strong>2. FROM</strong> — which table are you reading?</li>\n<li><strong>3. WHERE</strong> — go through the table <strong>row by row</strong>, testing the condition against that row''s actual values.</li>\n</ul>\n<p><strong>Example:</strong> for <code>SELECT Title FROM Album WHERE Price &lt;= 8</code>, check every row in turn: Skyline (Price 8) — passes. Wavelength (10) — fails. Horizon (12) — fails. Ember (6) — passes. Tidal (9) — fails. Result: Skyline, Ember.</p>", "question": "What is the safest way to work out which rows a WHERE condition returns?", "options": ["Check the condition against every row in the table, one row at a time", "Only check the very first and last rows, since the rows in between are assumed to follow the same pattern", "Count how many fields are listed after SELECT, since that always equals the number of matching rows", "Guess based on how the table happens to be sorted, without checking the condition itself"]}'::jsonb, '{"answer": 0, "explain": "Going row by row and testing the condition against each one is reliable. Skipping rows or guessing from the SELECT list is not."}'::jsonb),
('computer-science:2-2-3d-sql:tips:1c2add94', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'tips', 'mcq', 1, '{"readingTitle": "explain — Writing a query from a description (the three-part method)", "reading": "<p>You''ll be given a table and an English description of what''s needed, and asked to write the matching query. Break the description into three parts, in order:</p>\n<ul>\n<li><strong>Which fields?</strong> → after SELECT (or * for every field).</li>\n<li><strong>Which table?</strong> → after FROM.</li>\n<li><strong>Which rows?</strong> → any condition described → after WHERE.</li>\n</ul>\n<p><strong>Worked example:</strong> \"Show the name of every Squad player who plays Midfielder\" → fields = Name, table = Squad, condition = Position is Midfielder.</p>\n<p>Query: <code>SELECT Name FROM Squad WHERE Position = \"Midfielder\"</code></p>", "question": "Using the three-part method, what should come after WHERE for ''show every field for albums released before 2020''?", "options": ["A condition on the Year field", "SELECT *", "FROM Album", "The word Year on its own, since stating a field name is always enough to filter rows by that field"]}'::jsonb, '{"answer": 0, "explain": "WHERE holds the condition on the rows (Year < 2020). SELECT * and FROM Album belong in different parts of the query."}'::jsonb),
('computer-science:2-2-3d-sql:tips:cbfd534e', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'tips', 'mcq', 1, '{"readingTitle": "tip — Common exam traps: AND vs OR, and strict vs inclusive operators", "reading": "<p>Two mistakes come up again and again in SQL exam questions:</p>\n<ul>\n<li><strong>AND vs OR</strong> — AND needs every condition to be true (narrows the result down); OR needs only one to be true (can widen it). Read the English description carefully — \"and\" in a sentence doesn''t always mean the SQL keyword AND.</li>\n<li><strong>Strict vs inclusive operators</strong> — <code>&gt;</code> and <code>&lt;</code> exclude the exact boundary value; <code>&gt;=</code> and <code>&lt;=</code> include it. If a question says \"at least\" or \"or more\", that''s <code>&gt;=</code>; \"more than\" alone is <code>&gt;</code>.</li>\n</ul>\n<p>Before writing a final answer, re-read the English description once more and check your query against it, condition by condition.</p>", "question": "A question asks for players who scored ''at least 5 goals''. Which comparison should be used?", "options": ["Greater than or equal to 5, so that a player with exactly 5 goals is still included", "Greater than 5 on its own, so that a player with exactly 5 goals is excluded from the final result", "Less than or equal to 5", "Not equal to 5"]}'::jsonb, '{"answer": 0, "explain": "''At least 5'' includes the value 5 itself, so it needs greater than or equal to — not the strict greater than."}'::jsonb),
