('computer-science:2-2-3d-sql:match:a65e2790', 'computer-science', 'computer-science:2-2-3d-sql', '2.2.3d SQL', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “=”?", "options": ["Checks whether a field''s value exactly matches a given value", "Names the table a query reads its data from", "A field is one column of data; a record is one row — one complete set of field values", "Check whether a value is bigger-or-equal / smaller-or-equal, including an exact match"]}'::jsonb, '{"answer": 0, "explain": "“=” means: Checks whether a field''s value exactly matches a given value"}'::jsonb),
