('computer-science:2-2-3e-subprograms-and-random-numbers:exam:29676bcf', 'computer-science', 'computer-science:2-2-3e-subprograms-and-random-numbers', '2.2.3e Sub Programs and Random Numbers', 'exam', 'mcq', 1, '{"num": "Q1", "question": "<p>Tick <strong>one</strong> box to identify which keyword a function uses to send a value back to wherever it was called from.</p>", "options": ["return", "endfunction, since that keyword is what actually sends the function''s value back to the caller, not return", "function", "parameter"], "hint": "This keyword appears inside the function body, and immediately ends the function once it runs."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>return</strong></li></ul>\n</div>", "modelAnswer": "return."}'::jsonb),
